// Reshape the server's already-ranked response and GATE it by confidence.
// The server (GET /api/agent/products) does trigram+FTS+ranking and tags each
// result with match = exact|strong|partial|fuzzy. We split:
//   confident = exact|strong  -> the agent MAY offer directly
//   dudoso    = partial|fuzzy -> the agent must NEVER assert (pan->panela guard)
// Input item json = the raw server response.
const r = $input.first().json || {};
const results = Array.isArray(r.results) ? r.results : [];
const alternatives = Array.isArray(r.alternatives) ? r.alternatives : [];

const CONFIDENT = new Set(['exact', 'strong']);
const slim = p => ({
  id: p.id,
  name: p.name,
  price: p.price,
  in_stock: p.in_stock,
  size: p.size || null,
  match: p.match,
});

const confident = results.filter(p => CONFIDENT.has(p.match)).map(slim);
const dudoso = results.filter(p => !CONFIDENT.has(p.match)).map(slim);

// Ask-before-guessing whenever there is no single clear winner.
const needs_confirmation =
  r.status === 'multiple_matches' ||
  confident.length > 1 ||
  (confident.length === 0 && (dudoso.length > 0 || alternatives.length > 0));

let recommendation;
if (confident.length === 1 && r.status !== 'multiple_matches') {
  recommendation = `Match confiable: ofrece "${confident[0].name}" ($${confident[0].price}).`;
} else if (confident.length > 1) {
  recommendation = `Varias coincidencias confiables. NO elijas vos: preguntale al cliente cual quiere entre: ${confident.map(p => p.name).join(', ')}.`;
} else if (dudoso.length > 0) {
  recommendation = `SIN match confiable. Hay parecidos que probablemente NO son lo que pidio (${dudoso.map(p => p.name).join(', ')}). NO los ofrezcas como seguros: preguntá "no estoy seguro, te referis a ...?" antes de nada.`;
} else if (alternatives.length > 0) {
  recommendation = `No hay match exacto. Ofrece una alternativa como PREGUNTA, ej "no tengo eso, te sirve ${alternatives[0].name}?".`;
} else {
  recommendation = `No hay match para "${r.query || ''}". NO adivines ni ofrezcas nada. Pedile al cliente que sea mas especifico: que te diga el NOMBRE del producto puntual (marca y presentacion). El buscador trabaja por nombre, no por sintoma o uso.`;
}

return [{
  json: {
    status: r.status || 'not_found',
    requested: r.query || '',
    needs_confirmation,
    confident,   // seguros: se pueden ofrecer
    dudoso,      // NO ofrecer sin preguntar (guarda anti pan->panela)
    alternatives: alternatives.map(a => ({ ...slim(a), reason: a.reason })),
    recommendation,
  },
}];
